---@class LFightHudData
local LFightHudData = classX("LFightHudData",nil)

function LFightHudData:ctor(changeType,hurt,delay,floatHurtY)
    self._changeType = changeType
    self._hurt = hurt
    self._delay = delay
    self._floatHurtY = floatHurtY
    self._damageName = ""
    self._damageColor = ""
    self._numType = 0

    self.heroRace = 1

    local damageRef = changeType and GameTable.BattleDamageTypeRef[changeType] or nil
    if damageRef then
        self._damageName = I18nText(damageRef.prefixName)
        self._damageColor = damageRef.color
        self._numType = damageRef.numType
    else
        if ENABLE_FIGHT_LOG then
            printInfo("battle","伤害类型表(CombatDamageTypeRef)不存在配置，refId = " .. tostring(changeType))
        end
    end
end

function LFightHudData:GetChangeType()
    return self._changeType
end
function LFightHudData:GetHurt()
    return self._hurt
end
function LFightHudData:GetDelay()
    return self._delay
end
function LFightHudData:GetFloatHurtY()
    return self._floatHurtY
end

function LFightHudData:GetDamageName()
    return self._damageName
end

function LFightHudData:GetDamageColor()
    return self._damageColor
end

function LFightHudData:GetNumType()
    return self._numType
end

return LFightHudData
